import { useSelector, useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { add, less } from "../redux/dataReducerCart";
import './cart.css';
import { use } from "react";

function Cart() {
    const dispatch = useDispatch();
    const navigate = useNavigate();

    //נשלוף את הנתונים מהסטור
    //המערך של המוצרים בסל
    const robots = useSelector(s => s.cart.arr_cart);
    //הסכום הכולל של המוצרים בסל    
    const sum = useSelector(s => s.cart.total_amount);
    //הלקוח
    const currentUser = useSelector((state) => state.user.currentUser)

    //פונקציה שתמשמור את ההזמנה
    const handleFinishOrder = async () => {
        //אם המשתמש לא מחובר
        if (currentUser.customerName == "guest") {
            alert("עליך להתחבר למערכת על מנת להשלים את ההזמנה")
            navigate('/logIn');
            return;
        }

        //נבנה את אוביקט ההזמנה כדי לשלוח לשרת
        const orderObj = {
            customerCode: currentUser._id,
            robots: arr,
            sum: sum
        }

        try {
            //נקרא לשרת כדי לשמור את ההזמנה
            const response = await fetch("http://localhost:8080/api/shoppingApi/addShopping", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify(orderObj)
            })
            if (response.ok) {
                alert("ההזמנה נשמרה בהצלחה");
                navigate('/home');
            }
            else {
                alert("שגיאה בשמירת ההזמנה");
            }
        } catch (error) {
            console.error("Error:", error);
            alert("שגיאת תקשורת עם השרת");
        }
        }
        return (
            <div className="cart-container">
                <h1 className="cart-title">סל הקניות שלי ({arr.length} מוצרים)</h1>

                <div className="cart-content">
                    {/* צד ימין: רשימת המוצרים */}
                    <div className="cart-items-list">
                        {arr.map(a => (
                            <div className="cart-item-row" key={a._id}>
                                <div className="item-image">
                                    <img src={"http://localhost:8080/" + a.img} alt={a.robotName} />
                                </div>

                                <div className="item-info">
                                    <div className="item-header">
                                        <h2 className="item-name">{a.robotName}</h2>
                                        <p className="item-price-total">{a.price * a.count} ₪</p>
                                    </div>
                                    <p className="item-id">קוד מוצר: {a._id}</p>

                                    <div className="item-actions">
                                        <div className="quantity-selector">
                                            <button className="qty-btn" onClick={() => dispatch(less(a))}>-</button>
                                            <span className="qty-number">{a.count}</span>
                                            <button className="qty-btn" onClick={() => dispatch(add(a))}>+</button>
                                        </div>
                                        <h3 className="unit-price">מחיר ליחידה: {a.price} ₪</h3>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* צד שמאל: סיכום הזמנה */}
                    <div className="cart-summary">
                        <h2 className="summary-title">סיכום הזמנה</h2>
                        <div className="summary-row">
                            <span>משלוח:</span>
                            <span>חינם</span>
                        </div>
                        <div className="summary-row total">
                            <span>סה"כ לתשלום:</span>
                            <span className="total-amount">{sum} ₪</span>
                        </div>
                        <button className="checkout-btn" onClick={handleFinishOrder}>המשך לתשלום מאובטח</button>
                    </div>
                </div>
            </div>
        );
    
}

    export default Cart;
